export interface TrackPoint {
  x: number;
  y: number;
}

/** Маркер швидкості: на якому прогресі по трасі (0..1) який час (секунди від старту) */
export interface SpeedProfilePoint {
  progress: number;  // 0..1 — позиція на трасі
  time: number;      // секунди від старту кола
}

export interface TrackConfig {
  id: number;
  name: string;
  length: string;
  image: string;
  turns: number;
  svgPath: string;
  s1Point: TrackPoint | null;
  gridPositions: TrackPoint[];
  pitPositions: TrackPoint[];
  /** Профіль швидкості: масив точок {progress, time} для нерівномірного руху */
  speedProfile: SpeedProfilePoint[];
  /** Еталонний час кола (секунди) для якого визначено speedProfile */
  referenceLapTime: number;
}

